export const CITIES: City[] = RAW.map(function (r) {
  return { name: r[0], country: r[1], lat: r[2], lon: r[3], tz: r[4] };
});

function toRad(deg: number): number { return (deg * Math.PI) / 180; }

// Angular (earth-radius-agnostic) haversine — we only ever compare distances for "nearest".
function angularDist(lat1: number, lon1: number, lat2: number, lon2: number): number {
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat / 2) * Math.sin(dLat / 2)
    + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
  return 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

export function nearestCity(lat: number, lon: number): City | null {
  let best: City | null = null;
  let bestDist = Infinity;
  for (let i = 0; i < CITIES.length; i++) {
    const c = CITIES[i];
    const d = angularDist(lat, lon, c.lat, c.lon);
    if (d < bestDist) { bestDist = d; best = c; }
  }
  // Snap to the most-populous city within ~30km so a GPS fix labels the metro (Dhaka),
  // not a neighbourhood (Bhatara). CITIES is population-descending, so the first hit wins.
  // ponytail: ceiling — near a land border this can snap across a country (raw-nearest can too).
  const SNAP = 30 / 6371; // ~30km as an angular distance (radians)
  for (let i = 0; i < CITIES.length; i++) {
    if (angularDist(lat, lon, CITIES[i].lat, CITIES[i].lon) <= SNAP) return CITIES[i];
  }
  return best;
}

export function cityByTimezone(tz: string): City | null {
  for (let i = 0; i < CITIES.length; i++) {
    if (CITIES[i].tz === tz) return CITIES[i];
  }
  return null;
}

// Heuristic per-region day delta vs Umm al-Qura (Saudi) civil reckoning.
// Bangladesh's moon-sighting committee typically declares the new Hijri month one day
// after Umm al-Qura, so its civil Hijri date runs ~1 day behind. Every other country
// defaults to 0; users fine-tune with the manual "local sighting adjustment" knob.
const REGION_OFFSET: { [iso2: string]: number } = { BD: -1 };

export function regionOffsetFor(country: string): number {
  const v = REGION_OFFSET[country];
  return typeof v === 'number' ? v : 0;
}
